import React, { useState } from "react";
import axios from "axios";
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  Tooltip,
  Title,
  Legend,
  TimeScale
} from "chart.js";
import { FinancialController, CandlestickElement } from "chartjs-chart-financial";
import { Chart } from "react-chartjs-2";
import "chartjs-adapter-date-fns";

ChartJS.register(
  CategoryScale,
  LinearScale,
  BarElement,
  FinancialController,
  CandlestickElement,
  TimeScale,
  Tooltip,
  Title,
  Legend
);

const formatCurrency = (value) => {
  if (value == null) return "N/A";
  return `₹${Number(value).toLocaleString("en-IN")}`;
};

const formatNumber = (value, decimals = 2) => {
  if (value == null) return "N/A";
  return Number(value).toFixed(decimals);
};

const IndianStockDetails = () => {
  const [symbol, setSymbol] = useState("TCS.NS");
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  const fetchData = async () => {
    setError("");
    setLoading(true);
    setData(null);
    try {
      const res = await axios.get(`http://localhost:3000/api/stocks/${symbol}`);
      setData(res.data);
    } catch (err) {
      console.error(err);
      setError("Failed to fetch stock data.");
    } finally {
      setLoading(false);
    }
  };

  const renderCandlestickChart = () => {
    if (!data?.historical?.quotes?.length) return null;

    const candleData = data.historical.quotes.map((d) => ({
      x: new Date(d.date),
      o: d.open,
      h: d.high,
      l: d.low,
      c: d.close
    }));

    return (
      <div style={{ marginTop: "30px", width: "100%", maxWidth: "900px" }}>
        <h3>📊 Candlestick Chart</h3>
        <Chart
          type="candlestick"
          data={{
            datasets: [
              {
                label: `${data.symbol} OHLC`,
                data: candleData,
                borderColor: "#007bff",
                color: {
                  up: "#4CAF50",
                  down: "#F44336",
                  unchanged: "#999"
                }
              }
            ]
          }}
          options={{
            responsive: true,
            scales: {
              x: {
                type: "time",
                time: {
                  unit: "day"
                },
                ticks: {
                  autoSkip: true,
                  maxTicksLimit: 15
                }
              }
            },
            plugins: {
              tooltip: {
                callbacks: {
                  label: (ctx) => {
                    const v = ctx.raw;
                    return `O:${v.o}, H:${v.h}, L:${v.l}, C:${v.c}`;
                  }
                }
              }
            }
          }}
        />
      </div>
    );
  };

  const renderVolumeChart = () => {
    if (!data?.historical?.quotes?.length) return null;

    const labels = data.historical.quotes.map((d) => new Date(d.date));
    const volumes = data.historical.quotes.map((d) => d.volume);

    return (
      <div style={{ marginTop: "30px", width: "100%", maxWidth: "900px" }}>
        <h3>📊 Volume</h3>
        <Chart
          type="bar"
          data={{
            labels,
            datasets: [
              {
                label: "Volume",
                data: volumes,
                backgroundColor: "#28a745"
              }
            ]
          }}
          options={{
            responsive: true,
            scales: {
              x: {
                type: "time",
                time: {
                  unit: "day"
                }
              }
            }
          }}
        />
      </div>
    );
  };

  const renderDividends = () => {
    const divs = data?.historical?.events?.dividends;
    if (!divs?.length) return null;

    return (
      <div style={{ marginTop: "20px" }}>
        <h3>💰 Dividends</h3>
        <ul style={{ listStyle: "none", padding: 0 }}>
          {divs.map((d, i) => (
            <li key={i} style={{ marginBottom: "10px" }}>
              • {new Date(d.date * 1000).toLocaleDateString("en-IN")}:{" "}
              <strong>{formatCurrency(d.amount)}</strong>
            </li>
          ))}
        </ul>
      </div>
    );
  };

  const renderMetricCards = () => {
    if (!data) return null;

    const cards = [
      { label: "Market Cap", value: formatCurrency(data.marketCap) },
      { label: "PE Ratio", value: formatNumber(data.peRatio) },
      { label: "52W High", value: formatCurrency(data.fiftyTwoWeekHigh) },
      { label: "52W Low", value: formatCurrency(data.fiftyTwoWeekLow) }
    ];

    return (
      <div style={{
        display: "flex",
        gap: "20px",
        flexWrap: "wrap",
        marginTop: "20px"
      }}>
        {cards.map((card, i) => (
          <div key={i} style={{
            background: "#f8f9fa",
            padding: "15px 20px",
            borderRadius: "8px",
            minWidth: "150px",
            textAlign: "center",
            boxShadow: "0 0 10px rgba(0,0,0,0.1)"
          }}>
            <div style={{ fontSize: "14px", color: "#555" }}>{card.label}</div>
            <div style={{ fontSize: "18px", fontWeight: "bold", color: "#007bff" }}>{card.value}</div>
          </div>
        ))}
      </div>
    );
  };

  return (
    <div style={{ padding: "20px", fontFamily: "Arial, sans-serif" }}>
      <h2>📈 Indian Stock Details</h2>
      <div style={{ marginBottom: "10px" }}>
        <input
          type="text"
          value={symbol}
          onChange={(e) => setSymbol(e.target.value)}
          placeholder="Enter Symbol (e.g. TCS.NS)"
          style={{
            padding: "8px",
            width: "250px",
            marginRight: "10px",
            borderRadius: "4px",
            border: "1px solid #ccc"
          }}
        />
        <button
          onClick={fetchData}
          disabled={loading}
          style={{
            padding: "8px 16px",
            backgroundColor: "#007bff",
            color: "#fff",
            border: "none",
            borderRadius: "4px",
            cursor: "pointer"
          }}
        >
          {loading ? "Loading..." : "Get Details"}
        </button>
      </div>

      {error && <p style={{ color: "red" }}>{error}</p>}

      {data && (
        <>
          <h3>{data.name} ({data.symbol})</h3>
          <h1 style={{ color: data.change > 0 ? "green" : "red" }}>
            ₹{formatCurrency(data.price)} | Change: {formatNumber(data.change)} ({formatNumber(data.percentChange)}%)
          </h1>

          {renderMetricCards()}
          {renderCandlestickChart()}
          {renderVolumeChart()}
          {renderDividends()}
        </>
      )}
    </div>
  );
};

export default IndianStockDetails;
